/**
 * Unit tests for session-heartbeat-publisher (#1885).
 *
 * Mocks ONLY getProjectDir + HOME so the publisher writes into a temp
 * workspace. The rest is real fs + real parsing.
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync, readFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

const mockedCwd = vi.hoisted(() => ({ value: '/' }));
vi.mock('../../../lib/paths.js', async (orig) => {
  const actual = (await orig()) as Record<string, unknown>;
  return { ...actual, getProjectDir: () => mockedCwd.value };
});

import {
  sessionHeartbeatPublisher,
  parseCommitFromOutput,
  parsePushFromCommandAndOutput,
  parsePrFromOutput,
  classifyCommand,
} from '../../../posttool/bash/session-heartbeat-publisher.js';
import { getStateFilePath } from '../../../lib/session-state.js';
import { createTestContext } from '../../fixtures/test-context.js';
import type { HookInput } from '../../../types.js';

let workspace: string;
let testCtx: ReturnType<typeof createTestContext>;
const fakeHome = () => workspace; // we redirect via HOME env

beforeEach(() => {
  workspace = mkdtempSync(join(tmpdir(), 'ork-publisher-'));
  vi.stubEnv('HOME', workspace);
  testCtx = createTestContext();
});

afterEach(() => {
  vi.unstubAllEnvs();
  try {
    rmSync(workspace, { recursive: true, force: true });
  } catch {
    /* best-effort */
  }
});

function makeBashInput(command: string, output: string, sessionId = 'sid-test'): HookInput {
  return {
    tool_name: 'Bash',
    session_id: sessionId,
    tool_input: { command } as Record<string, unknown>,
    tool_output: output,
  };
}

function readStateFor(sessionId = 'sid-test', repo = 'platform') {
  const p = getStateFilePath(repo, sessionId, fakeHome());
  return JSON.parse(readFileSync(p, 'utf8'));
}

// ─── classifier ─────────────────────────────────────────────────

describe('classifyCommand', () => {
  it('classifies git commit', () => {
    expect(classifyCommand('git commit -m "x"')).toBe('commit');
    expect(classifyCommand('git -C /tmp commit -m "y"')).toBe('commit');
  });
  it('classifies git push', () => {
    expect(classifyCommand('git push')).toBe('push');
    expect(classifyCommand('git -C /a push origin main')).toBe('push');
  });
  it('classifies gh pr create / merge / ready', () => {
    expect(classifyCommand('gh pr create --title x')).toBe('pr');
    expect(classifyCommand('gh pr merge 123 --squash')).toBe('pr');
    expect(classifyCommand('gh pr ready 456')).toBe('pr');
  });
  it('returns null on unrelated commands', () => {
    expect(classifyCommand('ls -la')).toBeNull();
    expect(classifyCommand('npm test')).toBeNull();
    expect(classifyCommand('git status')).toBeNull(); // not structural
  });
});

// ─── parsers ────────────────────────────────────────────────────

describe('parseCommitFromOutput', () => {
  it('extracts sha + first-line msg from a git commit', () => {
    const out = '[main 5c9a906] feat(api): canonical seed-data migration\n 3 files changed';
    expect(parseCommitFromOutput(out)).toEqual({ sha: '5c9a906', msg: 'feat(api): canonical seed-data migration' });
  });
  it('handles detached HEAD', () => {
    const out = '[detached HEAD abc1234] fix bug';
    expect(parseCommitFromOutput(out)).toEqual({ sha: 'abc1234', msg: 'fix bug' });
  });
  it('returns null when no commit line present', () => {
    expect(parseCommitFromOutput('nothing here')).toBeNull();
  });
});

describe('parsePushFromCommandAndOutput', () => {
  it('parses a new-branch push', () => {
    const out = ' * [new branch]      feat/x -> feat/x';
    const r = parsePushFromCommandAndOutput('git push -u origin feat/x', out);
    expect(r?.branch).toBe('feat/x');
  });
  it('parses an update push', () => {
    const out = '   abc1234..def5678  feat/y -> feat/y';
    const r = parsePushFromCommandAndOutput('git push', out);
    expect(r?.branch).toBe('feat/y');
  });
  it('falls back to command when output unparseable', () => {
    const r = parsePushFromCommandAndOutput('git push origin feat/z', '');
    expect(r?.branch).toBe('feat/z');
  });
});

describe('parsePrFromOutput', () => {
  it('extracts PR number + url from `gh pr create` output', () => {
    const out = 'https://github.com/yo/repo/pull/1234';
    expect(parsePrFromOutput('gh pr create', out)).toEqual({
      number: 1234,
      url: 'https://github.com/yo/repo/pull/1234',
      state: 'open',
    });
  });
  it('marks draft when --draft flag is in command', () => {
    const r = parsePrFromOutput('gh pr create --draft', 'https://github.com/o/r/pull/9');
    expect(r?.state).toBe('draft');
  });
  it('marks merged when output mentions merged', () => {
    const r = parsePrFromOutput('gh pr merge 9', 'PR https://github.com/o/r/pull/9 is merged');
    expect(r?.state).toBe('merged');
  });
  it('returns null when no PR url in output', () => {
    expect(parsePrFromOutput('gh pr list', 'no pr here')).toBeNull();
  });
});

// ─── publisher hook integration ─────────────────────────────────

describe('sessionHeartbeatPublisher', () => {
  beforeEach(() => {
    mockedCwd.value = join(workspace, 'platform');
  });

  it('does nothing on non-Bash tool', () => {
    const r = sessionHeartbeatPublisher(
      { tool_name: 'Read', session_id: 's', tool_input: {} },
      testCtx,
    );
    expect(r.continue).toBe(true);
    expect(r.suppressOutput).toBe(true);
  });

  it('does nothing on unrelated Bash command', () => {
    const r = sessionHeartbeatPublisher(makeBashInput('ls', ''), testCtx);
    expect(r.continue).toBe(true);
    expect(r.suppressOutput).toBe(true);
  });

  it('writes commit info on git commit', () => {
    sessionHeartbeatPublisher(
      makeBashInput('git commit -m "x"', '[main 5c9a906] feat: x'),
      testCtx,
    );
    const state = readStateFor();
    expect(state.last_commit).toEqual({ sha: '5c9a906', msg: 'feat: x' });
    expect(state.status).toBe('running');
    expect(state.repo).toBe('platform');
  });

  it('writes push info on git push and preserves previous commit', () => {
    sessionHeartbeatPublisher(
      makeBashInput('git commit -m "x"', '[main 5c9a906] feat: x'),
      testCtx,
    );
    sessionHeartbeatPublisher(
      makeBashInput('git push origin feat/x', ' * [new branch]      feat/x -> feat/x'),
      testCtx,
    );
    const state = readStateFor();
    expect(state.last_commit).toEqual({ sha: '5c9a906', msg: 'feat: x' });
    expect(state.last_push?.branch).toBe('feat/x');
  });

  it('writes PR info on gh pr create', () => {
    sessionHeartbeatPublisher(
      makeBashInput('gh pr create --draft', 'https://github.com/yo/repo/pull/42'),
      testCtx,
    );
    const state = readStateFor();
    expect(state.last_pr).toEqual({
      number: 42,
      url: 'https://github.com/yo/repo/pull/42',
      state: 'draft',
    });
  });

  it('writes file at the expected layout — <home>/.claude/state/orchestkit/<repo>/<sid>.json', () => {
    sessionHeartbeatPublisher(
      makeBashInput('git commit -m "x"', '[main 5c9a906] feat: x', 'session-id-XYZ'),
      testCtx,
    );
    const p = join(workspace, '.claude', 'state', 'orchestkit', 'platform', 'session-id-XYZ.json');
    expect(() => readFileSync(p, 'utf8')).not.toThrow();
  });
});
